import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart, ResponsiveChartContainer, ChartsClipPath, LinePlot, ChartsXAxis, ChartsYAxis } from '@mui/x-charts';
import response from './response.json';

interface DailyEmissions {
  total: number;
  unit: string;
}

interface CategoryBreakdown {
  category: string;
  emissions: number;
}

interface CarbonData {
  widget: {
    id: string;
    app: string;
    version: string;
  };
  data: {
    dailyEmissions: DailyEmissions;
    categoryBreakdown: CategoryBreakdown[];
    monthlyTrend: number[];
  };
  meta: {
    theme: string;
    dataMode: string;
    layout: string;
    primaryColor: string;
    accentColor: string;
    chartTypes: string[];
  };
}

export default function Widget() {
  const carbonData = response.data as CarbonData;
  const { dailyEmissions, categoryBreakdown, monthlyTrend } = carbonData.data;
  const { primaryColor, accentColor } = carbonData.meta;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#333' }} elevation={2}>
      <CardContent sx={{ p: 2.5, color: '#fff' }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: primaryColor }}>
              Daily Carbon Footprint
            </Typography>
            <Typography variant="h4" fontWeight={600}>
              {dailyEmissions.total} {dailyEmissions.unit}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <PieChart
              series={[
                {
                  data: categoryBreakdown.map((item) => ({
                    label: item.category,
                    value: item.emissions,
                  })),
                  color: accentColor,
                },
              ]}
              sx={{
                '& .MuiPieChartLabel-root': {
                  fill: '#fff',
                },
              }}
            />
          </Box>

          <Box sx={{ width: '100%', height: 150 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: monthlyTrend,
                  color: primaryColor,
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  data: monthlyTrend.map((_, index) => index + 1),
                  id: 'months',
                },
              ]}
              yAxis={[{ id: 'emissions' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="months"
                tickLabelStyle={{ fontSize: 10, fill: '#fff' }}
              />
              <ChartsYAxis
                axisId="emissions"
                tickLabelStyle={{ fontSize: 10, fill: '#fff' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {categoryBreakdown.map((item, index) => (
              <Chip
                key={index}
                label={item.category}
                sx={{ backgroundColor: primaryColor, color: '#fff', fontSize: '12px', px: 1 }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
